#!/usr/bin/env python3
"""Generate missing Starter Plan lesson files for Days 68-90 across all disciplines."""
import sys
from pathlib import Path

PROJECT_ROOT = Path(__file__).resolve().parents[1]
if str(PROJECT_ROOT) not in sys.path:
    sys.path.insert(0, str(PROJECT_ROOT))
from backend.core.paths import STARTER_PLAN_DIR  # noqa: E402

BASE = STARTER_PLAN_DIR / "messages"
SCOPE = "\nScope note:\nThis is general educational content, not project review, engineering verification, code compliance confirmation, or construction approval."

def w(disc, day, title, matters, concept_lines, lens, checks, mistake, action):
    path = BASE / disc / f"day_{day:03d}.txt"
    if path.exists():
        print(f"  skip {disc}/day_{day:03d} (exists)")
        return
    concept = "\n".join(f"- {c}" for c in concept_lines)
    ck = "\n".join(f"- Check: {c}" for c in checks)
    content = (
        f"LUA BIM LABS Starter\nDay {day} - {title}\n\n"
        f"1. Why This Matters\n{matters}\n\n"
        f"2. Core Concept\n{concept}\n\n"
        f"3. Real Project Lens\n{lens}\n\n"
        f"4. BIM Check\n{ck}\n\n"
        f"5. Common Mistake\n{mistake}\n\n"
        f"6. Today's Action\n{action}"
        f"{SCOPE}"
    )
    path.parent.mkdir(parents=True, exist_ok=True)
    path.write_text(content, encoding="utf-8")
    print(f"  ✅ {disc}/day_{day:03d}")

